int add(int a, int b) // a and b are PARAMETERS
{
    return a + b;
}

int main()
{
    add(5, 3); // 5 and 3 are ARGUMENTS
}

#include <iostream>

using namespace std;

int multiply(int a, int b)
{
    return a * b;
}

int main()
{
    cout << multiply(4, 5) << endl;

    return 0;
}

int divide(int numerator, int denominator)
{
    return numerator / denominator;
}

cout << divide(10, 2); // 5
cout << divide(2, 10); // 0 — arguments swapped, wrong answer

int power(int base, int exponent = 2)
{
    int result = 1;
    for (int i = 0; i < exponent; i++)
    {
        result *= base;
    }
    return result;
}

cout << power(5) << endl;     // exponent defaults to 2 → 25
cout << power(5, 3) << endl;  // exponent explicitly 3 → 125

